2	
3	// Account model — CRUD for the accounts table (JSONB doc column).
4	// The accounts entity stores all fields in a JSONB doc: accountId, name, tier,
5	// segment, region, status, createdAt, plus embedded arrays for details, settings,
6	// preferences, team, billing, health_scores.
7	
8	export async function createAccount(client, data) {
9		await ensureSchema(client);
10		const doc = { ...data };
11		await client.query(
12			'INSERT INTO accounts (account_id, doc) VALUES ($1, $2) RETURNING doc',
13			[doc.accountId, JSON.stringify(doc)]
14		);
15		return doc;
16	}
17	
18	export async function getAccount(client, accountId) {
19		const res = await client.query('SELECT doc FROM accounts WHERE account_id = $1', [accountId]);
20		return res.rows[0]?.doc || null;
21	}
22	
23	export async function updateAccount(client, accountId, data) {
24		const existing = await getAccount(client, accountId);
25		if (!existing) return null;
26		const updated = { ...existing, ...data };
27		await client.query('UPDATE accounts SET doc = $1 WHERE account_id = $2', [JSON.stringify(updated), accountId]);
28		return updated;
29	}
30	
31	export async function deleteAccount(client, accountId) {
32		await client.query('DELETE FROM accounts WHERE account_id = $1', [accountId]);
33	}
34	
35	export async function listAccounts(client, filter = {}) {
36		const res = await client.query('SELECT doc FROM accounts LIMIT 100');
37		return res.rows.map(r => r.doc);
38	}
