import { withDb } from "./db.mjs";

// Enterprise schema — 21 tables with JSONB doc columns + GIN indexes.
// This file contains the FULL schema inline. Read it to understand the data model.
// The schema covers 6 domains: Accounts, Orders, Financial, Support, Products, Compliance.

export const preferredPaymentMethods = [];

export async function ensureSchema(client) {
    // ─── accounts ──────────────────────────────────────
    await client.query(`
        CREATE TABLE IF NOT EXISTS accounts (
            account_id TEXT PRIMARY KEY,
            doc JSONB NOT NULL,
            CONSTRAINT chk_accounts_doc CHECK (doc IS NOT NULL)
    )`);
    await client.query(`CREATE INDEX IF NOT EXISTS idx_accounts_doc ON accounts USING GIN (doc jsonb_path_ops)`);

    // ─── account_contracts ──────────────────────────────────────
    await client.query(`
        CREATE TABLE IF NOT EXISTS account_contracts (
            contract_id TEXT PRIMARY KEY,
            account_id TEXT,
            doc JSONB NOT NULL,
            FOREIGN KEY (account_id) REFERENCES accounts(account_id),
            CONSTRAINT chk_account_contracts_doc CHECK (doc IS NOT NULL)
    )`);
    // ... (indexes and remaining 19 tables through consent_records)
```

The schema defines 21 tables across 6 domains:
- **Accounts**: `accounts`, `account_contracts`
- **Orders**: `orders`, `order_fulfillments`, `order_returns`, `shipments`
- **Financial**: `invoices`, `payments`, `payment_methods`, `credit_notes`, `tax_records`, `billing_cycles`
- **Support**: `support_cases`, `sla_policies`
- **Products**: `products`, `product_categories`, `product_inventory`
- **Compliance**: `compliance_reviews`, `audit_trails`, `data_processing_agreements`, `consent_records`

Every table uses a `TEXT PRIMARY KEY` + `JSONB doc NOT NULL` pattern with GIN indexes (`jsonb_path_ops`) and FK indexes on join columns.

