export function validateEntity(entityName, data) {
  const entity = ENTITIES[entityName];
  if (!entity) throw new Error(`Unknown entity: ${entityName}`);

  for (const [field, config] of Object.entries(entity.fields)) {
    if (config.required && !data[field]) {
      throw new Error(`Required field missing: ${field}`);
    }
    if (data[field] && config.enum && !config.enum.includes(data[field])) {
      throw new Error(`Invalid value for ${field}: ${data[field]}`);
    }
  }
  return true;
}
