  const result = await db.query(
    'SELECT data FROM entities WHERE entity_type = $1 AND entity_id = $2',
    ['accounts', id]
  );

  if (result.rows.length === 0) return null;
  return result.rows[0].data;
}

export async function updateAccount(id, updates) {
  const db = await getDb();

  const existing = await getAccount(id);
  if (!existing) throw new Error(`Account not found: ${id}`);

  const updated = {
    ...existing,
    ...updates,
    updatedAt: new Date().toISOString(),
  };

  // Validate the updated account
  validateEntity('accounts', updated);

  await db.query(
    'UPDATE entities SET data = $1 WHERE entity_type = $2 AND entity_id = $3',
    [JSON.stringify(updated), 'accounts', id]
  );

  return updated;
}

export async function listAccounts(filters = {}) {
  const db = await getDb();

  let query = 'SELECT data FROM entities WHERE entity_type = $1';
  const params = ['accounts'];

  // Apply filters using JSONB operators
  if (filters.status) {
    query += ` AND data->>'status' = $${params.length + 1}`;
    params.push(filters.status);
  }

  if (filters.tier) {
    query += ` AND data->>'tier' = $${params.length + 1}`;
    params.push(filters.tier);
  }

  const result = await db.query(query, params);
  return result.rows.map(row => row.data);
}
