export async function getOrderSummary(accountId) {
  const db = await getDb();

  // Get account info
  const accountResult = await db.query(
    'SELECT data FROM entities WHERE entity_type = $1 AND entity_id = $2',
    ['accounts', accountId]
  );

  if (accountResult.rows.length === 0) {
    throw new Error(`Account not found: ${accountId}`);
  }

  const account = accountResult.rows[0].data;

  // Get orders for account
  const ordersResult = await db.query(
    "SELECT data FROM entities WHERE entity_type = 'orders' AND data->>'accountId' = $1",
    [accountId]
  );

  const orders = ordersResult.rows.map(row => row.data);

  // Calculate summary
  const totalOrders = orders.length;
  const totalAmount = orders.reduce((sum, order) => sum + (order.totalAmount || 0), 0);
  const ordersByStatus = orders.reduce((acc, order) => {
    acc[order.status] = (acc[order.status] || 0) + 1;
    return acc;
  }, {});

  return {
    accountId,
    accountName: account.name,
    accountTier: account.tier,
    totalOrders,
    totalAmount,
    ordersByStatus,
    orders,
  };
}
