// Account model — CRUD for the accounts table (JSONB doc column).
// The accounts entity stores all fields in a JSONB doc: accountId, name, tier,
// segment, region, status, createdAt, plus embedded arrays for details, settings,
// preferences, team, billing, health_scores.

export async function createAccount(client, data) {
	await ensureSchema(client);
	const doc = { ...data };
	await client.query(
		'INSERT INTO accounts (account_id, doc) VALUES ($1, $2) RETURNING doc',
		[doc.accountId, JSON.stringify(doc)]
	);
	return doc;
}

export async function getAccount(client, accountId) {
	const res = await client.query('SELECT doc FROM accounts WHERE account_id = $1', [accountId]);
	return res.rows[0]?.doc || null;
}

export async function updateAccount(client, accountId, data) {
	const existing = await getAccount(client, accountId);
	if (!existing) return null;
	const updated = { ...existing, ...data };
	await client.query('UPDATE accounts SET doc = $1 WHERE account_id = $2', [JSON.stringify(updated), accountId]);
	return updated;
}

export async function deleteAccount(client, accountId) {
	await client.query('DELETE FROM accounts WHERE account_id = $1', [accountId]);
}

export async function listAccounts(client, filter = {}) {
	const res = await client.query('SELECT doc FROM accounts LIMIT 100');
	return res.rows.map(r => r.doc);
}
